body.script:
var svgObject = document.getElementById('atlas-svg');
var panZoomInstance = null;

// Must match the maxZoom passed into svgPanZoom() below
var CONFIGURED_MAX_ZOOM = 20;
var NODE_ZOOM_LEVEL = 3;

function alignTop() {
    if (!panZoomInstance) return;
    var sizes = panZoomInstance.getSizes();
    var contentHeight = sizes.viewBox.height * sizes.realZoom;
    var offsetY = (sizes.height - contentHeight) / 2;
    if (offsetY > 0) {
        var currentPan = panZoomInstance.getPan();
        panZoomInstance.pan({ x: currentPan.x, y: currentPan.y - offsetY });
    }
}

// Correctly computes an element's bounding box in ROOT SVG coordinates,
// accounting for all ancestor transforms (unlike raw getBBox()).
function getGlobalBBox(el, svgRoot) {
    var bbox = el.getBBox();
    var ctm = el.getCTM();

    console.log('Atlas debug: raw local bbox = x:' + bbox.x + ' y:' + bbox.y + ' w:' + bbox.width + ' h:' + bbox.height);

    if (!ctm) {
        console.warn('Atlas: getCTM() returned null, falling back to raw bbox (may be inaccurate)');
        return bbox;
    }

    var corners = [
        svgRoot.createSVGPoint(),
        svgRoot.createSVGPoint(),
        svgRoot.createSVGPoint(),
        svgRoot.createSVGPoint()
    ];
    corners[0].x = bbox.x;               corners[0].y = bbox.y;
    corners[1].x = bbox.x + bbox.width;  corners[1].y = bbox.y;
    corners[2].x = bbox.x + bbox.width;  corners[2].y = bbox.y + bbox.height;
    corners[3].x = bbox.x;               corners[3].y = bbox.y + bbox.height;

    var transformed = corners.map(function(pt) { return pt.matrixTransform(ctm); });
    var xs = transformed.map(function(p) { return p.x; });
    var ys = transformed.map(function(p) { return p.y; });

    var minX = Math.min.apply(null, xs);
    var maxX = Math.max.apply(null, xs);
    var minY = Math.min.apply(null, ys);
    var maxY = Math.max.apply(null, ys);

    var globalBBox = { x: minX, y: minY, width: maxX - minX, height: maxY - minY };
    console.log('Atlas debug: computed global bbox = x:' + globalBBox.x + ' y:' + globalBBox.y + ' w:' + globalBBox.width + ' h:' + globalBBox.height);
    return globalBBox;
}

function goToNode(nodeId) {
    var svgDoc = svgObject.contentDocument;
    if (!svgDoc) {
        console.warn('Atlas: could not access SVG document (contentDocument is null)');
        return;
    }

    var target = svgDoc.getElementById(nodeId);
    if (!target) {
        console.warn('Atlas: node not found:', nodeId);
        return;
    }

    console.log('Atlas: found node, navigating to', nodeId);

    var svgRoot = svgDoc.documentElement;
    var bbox = getGlobalBBox(target, svgRoot);

    var cx = bbox.x + bbox.width / 2;
    var cy = bbox.y + bbox.height / 2;

    var zoom = Math.min(NODE_ZOOM_LEVEL, CONFIGURED_MAX_ZOOM);
    panZoomInstance.zoom(zoom);

    var newSizes = panZoomInstance.getSizes();
    var panX = newSizes.width / 2 - cx * newSizes.realZoom;
    var panY = newSizes.height / 2 - cy * newSizes.realZoom;

    console.log('Atlas debug: target center (cx,cy) =', cx, cy, '| pan target =', panX, panY);

    panZoomInstance.pan({ x: panX, y: panY });

    highlightNode(target);
}

function highlightNode(target) {
    var original = target.getAttribute('stroke');
    var originalWidth = target.getAttribute('stroke-width');

    target.setAttribute('stroke', '#FFD700');
    target.setAttribute('stroke-width', '4');

    setTimeout(function() {
        if (original !== null) {
            target.setAttribute('stroke', original);
        } else {
            target.removeAttribute('stroke');
        }
        if (originalWidth !== null) {
            target.setAttribute('stroke-width', originalWidth);
        } else {
            target.removeAttribute('stroke-width');
        }
    }, 2500);
}

function initPanZoom() {
    panZoomInstance = svgPanZoom(svgObject, {
        zoomEnabled: true,
        controlIconsEnabled: true,
        fit: true,
        center: true,
        minZoom: 0.5,
        maxZoom: CONFIGURED_MAX_ZOOM
    });

    var hash = window.location.hash.replace('#', '');
    if (hash) {
        console.log('Atlas: hash detected on load:', hash);
        setTimeout(function() {
            goToNode(hash);
        }, 100);
    } else {
        alignTop();
    }
}

svgObject.addEventListener('load', initPanZoom);

window.addEventListener('resize', function() {
    if (!panZoomInstance) return;
    panZoomInstance.resize();
    panZoomInstance.fit();
    panZoomInstance.center();
    alignTop();
});

window.addEventListener('hashchange', function() {
    var hash = window.location.hash.replace('#', '');
    if (hash) goToNode(hash);
});
